def max_depth_of_nested_list(s):
    current_depth = 0
    max_depth = 0

    for char in s:
        if char == '[': 
            current_depth += 1
            max_depth = max(max_depth, current_depth)
        elif char == ']': 
            current_depth -= 1

    return max_depth

nested_list_string = input()
result = max_depth_of_nested_list(nested_list_string)
print(result)
